var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"이상하군요.","JPN":"おかしいですね。","ENG":"How odd.","TWN":"真奇怪。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_UNIT_AIR_DRONE_START"},{"id":"L3_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"GPS 정보에 따르면 여기가 아르세니코 패밀리와 접선하기로 한 곳입니다만.","JPN":"GPS情報によると、ここがアルセニコファミリーと接触する場所ですが。","ENG":"According to the GPS coordinates, this is the rendezvous point agreed upon with the Arsenicos.","TWN":"根據GPS資訊，這裡就是跟阿塞妮克家族接頭的地方。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"이런 전쟁터에서 만나자고 하다니 역시 휴먼들의 취향은 이해할 수 없군요.","JPN":"こんな戦場で待ち合わせをするなんて、やはりヒューマンの好みは理解できません。","ENG":"I could never understand the humans' idiosyncrasies, asking to meet in a battlefield like this.","TWN":"竟然約在這種戰場上，果然人類的思維無法理解。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"리, 리타! 가족 사이에 총부리를 들이밀 필요는 없잖니!","JPN":"リ、リタ！　家族同士で銃口を向ける必要はないじゃないか！","ENG":"R-Rita! There's no need to point guns at your family!","TWN":"麗、麗塔！家人之間沒必要舉槍相向吧！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"나도 너도 패밀리를 어떻게든 살려 보자는 거 아니냐.","JPN":"私も君も、ファミリーが生き残る術を模索しているだけだと思わないか？","ENG":"We're both just trying to do what's best for the organization.","TWN":"你和我終歸都是為了這個家族不是嗎。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"그저 방법이 달랐을 뿐이야. 그러니까 그 총은 이제 그만 내려 놓고......!","JPN":"ただその方法が異なるだけだ。だからその銃はしまって、話を……！","ENG":"We just had different approaches. So why don't you put the gun down and—","TWN":"只不過是方法不同而已。所以，現在把槍放下……！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......역겨운 놈. 넌 돼지 먹이로 주기도 아까워.","JPN":"……今更媚びを売る姿に反吐が出る。お前は豚の餌になることすらもったいないな。","ENG":"You disgust me. You're not even fit for pigswill.","TWN":"……噁心的傢伙，你不配。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"안면 스캔을 통한 신원 확인 완료. 의뢰인, 리타 아르세니코.","JPN":"顔面スキャンによる身元確認完了。依頼者、リタ・アルセニコ。","ENG":"Facial scan and recognition complete. Confirmed as the client, Rita Arsenico.","TWN":"面部掃描身份確認完畢。委託人，麗塔·阿塞妮克。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_UNIT_AIR_DRONE_START"},{"id":"L17_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"뭐지, 이건? 해적들이 쓰는 드론인가?","JPN":"なんだこれ？　海賊が使うドローンか？","ENG":"And what's this now? Some kind of pirate drone?","TWN":"這是，什麼？是海盜們使用的無人機？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"반갑습니다. 호라이즌 파이낸스의 대표이사, 호라이즌입니다.","JPN":"はじめまして。ホライズン・ファイナンスの代表取締役、ホライズンです。","ENG":"Greetings. I am Horizon, the CEO of Horizon Finance.","TWN":"見到您很高興。我是地平線金融的老闆，地平線本人。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"호라이즌이라고? 너 따위 고철이?","JPN":"ホライズンだと？　この鉄くずが？","ENG":"You're Horizon? A piece of junk like you?","TWN":"地平線？一個破銅爛鐵？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"너 따위라는 표현은 인정할 수 없군요.","JPN":"「鉄くず」という表現は認められませんね。","ENG":"I must protest this description of me.","TWN":"破銅爛鐵這個說法我不認可。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"내구성과 신뢰성을 고려했을 때, 물렁물렁한 단백질 반죽과 고철 중 무엇이 우월한지는 자명한 사실입니다.","JPN":"耐久性と信頼性を考慮すれば、ぷよぷよなタンパク質の塊と鉄、どちらが優秀なのかは明らかです。","ENG":"If you consider the durability and reliability of our respective bodies, you must concede I'm far superior to your mishmash of malleable proteins.","TWN":"考慮到耐久性和可靠性，軟綿綿蛋白質麵團和廢鐵…這兩者中哪個好不言自明。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"하긴, 주식도 인공지능 말대로 사는 세상이라지.","JPN":"まあ、株も人工知能に言われたとおりに買うご時世だし。","ENG":"I suppose A.I. controls everything nowadays, even the stock market.","TWN":"也是，現在買賣股票也全靠人工智慧了。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"평의회 눈치도 안 보고 만나겠다길래 별난 녀석이다 싶었는데, 소문대로군.","JPN":"評議会のことなんか気にせず会えると言うから変わった奴だと思ったが、噂どおりだな。","ENG":"I was wondering who'd be outrageous enough to ignore the Council and meet me... and now I see why.","TWN":"聽說你們不怕評議會，覺得很有個性，果然不同凡響。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"감상은 그 정도면 충분합니다. 호출한 용건을 듣고 싶군요.","JPN":"初対面の印象はそれぐらいで十分です。呼び出した要件をお聞きしましょう。","ENG":"That's quite enough admiring. Now tell me why you asked to see me.","TWN":"感言就到此為止，請說說你的目的。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"돈이 필요해서 불렀다. 네 경력에 한 줄 그을 만큼 큰 거래가 될 거야.","JPN":"金が必要だ。お前の経歴に残るくらい、大口の取引になるだろう。","ENG":"I called you because I needed money. This deal will be so big it'll leave quite a mark on your resume.","TWN":"我需要錢，這將是你業績金額中最為可觀一筆數目。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"대출해 드리기 전에 질문이 있습니다. 용도가 뭡니까?","JPN":"貸し出す前に質問があります。用途は何ですか？","ENG":"I do have one question before I grant you the loan. How do you plan to use it?","TWN":"借給你之前我只有一個問題。這筆錢的用途是什麼？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"도둑놈들 입 틀어막기.","JPN":"泥棒の連中の口止め料。","ENG":"To shut up a bunch of scoundrels.","TWN":"堵住那群小偷們的嘴。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"거액이 필요하겠군요.","JPN":"巨額が必要ですね。","ENG":"It sounds like you'll need a considerable sum then.","TWN":"看來需要巨額資金了。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"빌려 줄 수 있는지, 없는지만 말해. 몸뚱이를 팔아서라도 변제할 테니까.","JPN":"貸してくれるかどうかだけ言え。体を売ってでも返済してやる。","ENG":"Just tell me if you can lend it to me or not. I'll pay you back no matter what. I'll sell my own body if I need to.","TWN":"就說能不能借吧。我就算賣了自己也會還錢的。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"월납입금만 성실하게 상환한다면 자금은 얼마든지 융통해 드릴 수 있습니다.","JPN":"月払い金さえ誠実に返済できるなら、資金はいくらでも融通できます。","ENG":"I can lend you all the money you need, so long as you faithfully remit your monthly installments.","TWN":"只要每月能夠如期還款，要借多少錢都可以。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"그런데 이건 조직을 위해서입니까? 아니면 아버지를 위해서입니까?","JPN":"ところでこれは組織のためですか？　それとも父親のためですか？","ENG":"But is this for the sake of your organization? Or your father?","TWN":"但這是為了組織？還是為了父親？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......사채꾼도 아는 걸 보니 우리 집 가족사가 온 세상에 다 퍼졌나 보군.","JPN":"……闇金業者も知っているってことは、うちの家庭事情は世界中に広まったようだな。","ENG":"So the story of my family spread far enough, even loan sharks know about it.","TWN":"……連你們都知道了，看來我們家的家族史已經傳遍全世界了。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"이 일을 하다 보면 사소한 이야기도 주워 듣게 됩니다. 그래서 선택한 거기도 하고요.","JPN":"この仕事をしていると些細な話でも流れてくるものです。なので、あなたの呼び出しに応じたわけです。","ENG":"One comes across many stories in this line of business. That's partly why I chose this vocation.","TWN":"做這行久了，總會聽到一些八卦的事情。所以才選擇這一行。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"대답은?","JPN":"答えは？","ENG":"Well, which is it?","TWN":"你的回答是？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아버지를 위해서.","JPN":"父のために。","ENG":"It's for my father.","TWN":"為了父親。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"좋습니다. 만기일 전까지 이자는 2.5%이니 상환일을 준수해 주십시오.","JPN":"いいでしょう。満期日前までの利息は2.5％となりますので、支払い期日は守ってくださいね。","ENG":"Very well. The interest rate is 2.5% until maturity. Please don't be late on your payments.","TWN":"好的。到期日之前的利息為2.5%，請遵守還款日期。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"2.5%......? 그런 이자율로 사업이 돌아가나?","JPN":"2.5％……？　そんな利子で商売になるのか？","ENG":"2.5%......? How can you keep your business running with that kind of interest rate?","TWN":"2.5%……？這樣的利率能賺錢嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"상환일을 넘기기 전까지는 다들 그렇게 말하더군요.","JPN":"償還日が過ぎる前までは皆そんなことを言っていました。","ENG":"That's what everyone says until they're late on their payments.","TWN":"在超過還款日期之前，所有人都這麼說。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"하지만 2.5%라고 해도 조직 내의 입지가 위태로워진 당신에게는 거액이겠죠.","JPN":"しかし2.5％とはいえ、組織内の立場が危うくなっているあなたには巨額でしょう。","ENG":"But I'm sure even 2.5% is a large sum for you, given your currently precarious position in the organization.","TWN":"即使是只有2.5%，但這對於在組織內地位岌岌可危的你來說，也是一筆鉅款。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"그러니 당신에게 한 가지 거절하지 못할 제안을 하려고 합니다. 리타 아르세니코.","JPN":"そんなあなたに一つ断れない提案をしようと思います、リタ・アルセニコ。","ENG":"And as such, I'd like to make you an offer you can't refuse, Rita Arsenico.","TWN":"所以我想向你提出一個無法拒絕的提議。麗塔·阿塞妮克。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"영화를 너무 많이 봤군. 진짜 마피아는 그런 멋들어진 말 안 써.","JPN":"映画の観すぎだな。本物のマフィアはそんな格好つけた台詞を使わないぞ。","ENG":"Someone's been watching too many movies. Real mafiosos don't talk all fancy like that.","TWN":"看來你是電影看多了。真正的黑手黨不會說那種帥氣的話。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L46_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"더러운 휴먼 놈들은 기록 영상에서도 거짓말뿐이군요.","JPN":"汚らわしいヒューマンたちは記録映像ですら、嘘だらけなんですね。","ENG":"You vile humans are full of lies, even in your historical video logs.","TWN":"骯髒的人類，在記錄視頻中也是謊話連篇。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_COMBAT_ALL_HIT_ELECTRIC_BIG"},{"id":"L47_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"저의 제안은 다음과 같습니다.","JPN":"私の提案は次のとおりです。","ENG":"My offer is this.","TWN":"我的提議如下。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"제 밑에서 일하십시오. 그러면 이자 없이 원금만 받도록 하겠습니다.","JPN":"私の下で働いてください。そうすれば利子なしで元金だけ頂くことにします。","ENG":"Work for me. And I'll loan you the money interest free.","TWN":"你必須在我手下工作。如果這樣的話，我就只收本金，不收你利息。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"뭐? 너도 내 능력을 돈벌이로 쓸 생각이냐?","JPN":"は？　お前も私の能力を金儲けに使うつもりか？","ENG":"What? Are you thinking of making money off my abilities too?","TWN":"什麼嘛？你也想利用我的能力賺錢？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"저 대신 수금원을 맡아줄 사람이 필요할 뿐입니다.","JPN":"私の代わりに集金係を務めてくれる人が必要なだけです。","ENG":"All I need is for someone to collect money on my behalf.","TWN":"我只是需要一個代替我的收款員。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"뒤처리 비용을 생각하면 실력 행사보다는 위협 쪽이 더 저렴하니까요.","JPN":"後始末の費用を考えると、実力行使より脅した方が安く済みますから。","ENG":"Given the cleanup costs, merely intimidating our clients is cheaper than actual use of force.","TWN":"考慮到善後處理費用，比起實力，威脅可能更便宜。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"특히나 당신처럼 사나운 인상이라면 안성맞춤이죠.","JPN":"特にあなたみたいな険しい印象の人ならうってつけです。","ENG":"And someone as mean-looking as you would be perfect for the job.","TWN":"特別是像你這種兇神惡煞的長相，非常合適。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"남의 낯짝 가지고 잘도 떠드는군.","JPN":"当人の前でよくそんなことが言えるな。","ENG":"You're not exactly helping yourself saying that.","TWN":"你這是人身攻擊。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"우리 업계에선 칭찬입니다.","JPN":"この業界では褒め言葉です。","ENG":"It's meant to be a compliment, in my line of business.","TWN":"在我們這個行業，這是讚美。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"그래서, 대답은?","JPN":"それで、答えは？","ENG":"So, what do you say?","TWN":"所以，你的回答是？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"호라이즌의 개로 전락했다는 소문이 퍼지니 나에 대한 관심도 빠르게 식더군.","JPN":"ホライズンの犬に転落したという噂が広まると、私に寄せられた関心も一気に薄れていった。","ENG":"When the rumor spread that I was reduced to working for Horizon, everyone got disinterested in me quickly.","TWN":"隨著淪為地平線走狗的傳聞流傳開來，對我的關注也快速冷卻了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"사실은 사채업자 시중이나 들어야 할 만큼 쓸모 없는 년이었다고 여겼을지도 모르고......","JPN":"所詮は闇金業者にこき使われる程度の、役に立たない人間と思われただけかもしれないし……","ENG":"Maybe they were convinced that I'm no better than a petty servant for a loan shark...","TWN":"也可能被認為是只配做放貸人隨從的廢物……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"호라이즌이 자기를 협박하던 테러 조직 두 군데를 파산시킨 전적 때문일지도 모르지.","JPN":"ホライズンが自分を脅迫していたテロ組織二ヶ所を破産させた戦績の影響かもしれない。","ENG":"Or maybe it was because of Horizon's track record, bankrupting two terrorist organizations that threatened him.","TWN":"也可能是地平線將兩個威脅自己的破壞分子組織搞破產的緣故吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"하지만 결국 내가 지킨 건 껍데기만 남은 조직이었어.","JPN":"しかし結局、私が守ったのは抜け殻となった組織だった。","ENG":"Either way, I only ended up saving the organization in name only.","TWN":"但最終，我守護的是只剩下空殼的組織。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"겉만 번지르르하고 속은 이미 썩어 없어진 뒤였지.","JPN":"表面だけの存在で、中身はとっくに腐りきってしまった後だった。","ENG":"It may have looked all fancy on the outside, but everything had rotted away on the inside.","TWN":"表面光鮮亮麗，但裡面已經腐敗了。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아니, 어쩌면 아버지가 지키려고 했던 건 처음부터 없었을지도 몰라.","JPN":"いや、もしかしたら父が守ろうとしたものは、最初から存在しなかったかもしれない。","ENG":"Maybe the Family my father was trying to protect never existed in the first place.","TWN":"不，或許父親要守護的東西，可能從一開始就不曾存在過。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"내가 아는 세상은 그런 쓰레기들 투성이였어.","JPN":"私の知っている世界なんてものは、そんなクズだらけの掃きだめだった。","ENG":"The world I knew was full of scumbags like that.","TWN":"我所知道的世界全是這些垃圾。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"호라이즌과 동업하게 된 뒤에도 한동안은 그런 줄 알았지.","JPN":"ホライズンと仕事を始めた後も、しばらくはそう思っていた。","ENG":"And I believed that for a while during my partnership with Horizon.","TWN":"跟地平線共事之後，我的世界也沒什麼改變。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......그 착해 빠진 꼬맹이를 만나기 전까지는.","JPN":"……あのお人好しのガキに出会うまでは。","ENG":"... That is, until I ran into that kid, who was too nice for her own good.","TWN":"……在遇到那個善良的小鬼之前。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};